try {
    if (!fileName || fileName.indexOf("..") !== -1 || fileName.indexOf("/") !== -1 || fileName.indexOf("\\") !== -1) {
        throw new Error("fileName must not be empty or contain path separators or '..': " + fileName);
    }
    if (!folderName || folderName.indexOf("..") !== -1 || folderName.indexOf("/") !== -1 || folderName.indexOf("\\") !== -1) {
        throw new Error("folderName must not be empty or contain path separators or '..': " + folderName);
    }

    var zipPath = folderName + "/" + fileName;

    Things["SystemRepository"].SaveBinary({
        path: zipPath,
        content: zipContent
    });

    Things["SystemRepository"].ExtractZipArchive({
        zipFileName: zipPath,
        path: folderName
    });

    Resources["SourceControlFunctions"].ImportSourceControlledEntities({
        repositoryName: "SystemRepository",
        path: folderName,
        useDefaultDataProvider: true,
        withSubsystems: false,
        overwritePropertyValues: true,
        overwriteConfigurationTableValues: true
    });

    result = "Imported entities from " + zipPath + " into folder " + folderName + ".";
} catch (err) {
    logger.error("VPS.Development.MCP.Management_TS.ImportEntityZip failed: " + err.message);
    throw err;
}

var startTime = Date.now();
try {
    if (!thingName) {
        throw new Error("thingName must not be empty");
    }
    if (!serviceName) {
        throw new Error("serviceName must not be empty");
    }
    if (!Things[thingName]) {
        throw new Error("Thing '" + thingName + "' does not exist");
    }
    if (typeof Things[thingName][serviceName] !== "function") {
        throw new Error("Service '" + serviceName + "' does not exist on Thing '" + thingName + "'");
    }

    var rawResult = Things[thingName][serviceName](params || {});

    var serializedResult;
    if (rawResult && typeof rawResult.ToJSON === "function") {
        serializedResult = rawResult.ToJSON();
    } else if (rawResult instanceof Date) {
        serializedResult = rawResult.toISOString();
    } else {
        serializedResult = rawResult;
    }

    result = {
        success: true,
        result: serializedResult,
        executionTimeMs: Date.now() - startTime,
        error: null
    };
} catch (err) {
    logger.error("VPS.Development.MCP.Management_TS.ExecuteService failed: " + err.message);
    result = {
        success: false,
        result: null,
        executionTimeMs: Date.now() - startTime,
        error: err.message
    };
}
